// Reads secrets from n8n environment variables so they never live in this file.
const env = $env;
const PLAID_ENV = (env.PLAID_ENV || 'production').toLowerCase();
const host = PLAID_ENV === 'sandbox' ? 'https://sandbox.plaid.com'
           : PLAID_ENV === 'development' ? 'https://development.plaid.com'
           : 'https://production.plaid.com';
const lookback = Number(env.PLAID_LOOKBACK_DAYS || 90);
const end = new Date();
const start = new Date();
start.setDate(end.getDate() - lookback);
const fmt = (d) => d.toISOString().slice(0, 10);
return [{ json: {
  plaidUrl: host + '/transactions/get',
  reqBody: {
    client_id: env.PLAID_CLIENT_ID,
    secret: env.PLAID_SECRET,
    access_token: env.PLAID_ACCESS_TOKEN,
    start_date: fmt(start),
    end_date: fmt(end),
    options: { count: 500, offset: 0 }
  }
}}];

// Flatten Plaid response into Graeham's canonical row schema.
const res = $json;
const accts = {};
(res.accounts || []).forEach(a => { accts[a.account_id] = (a.name || '') + ' ...' + (a.mask || ''); });
const txns = res.transactions || [];
return txns.map(t => ({ json: {
  txn_id: t.transaction_id,
  date: t.date,
  account: accts[t.account_id] || t.account_id,
  merchant: t.merchant_name || t.name,
  category: (t.personal_finance_category && t.personal_finance_category.primary) || (Array.isArray(t.category) ? t.category.join(' > ') : ''),
  amount: t.amount,
  currency: t.iso_currency_code || 'USD',
  pending: t.pending,
  notes: t.name,
  receipt_match: ''
}}));
